+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import type { Trait } from '../../trait/types';
+import type { World } from '../../world';
+import type { EventType, QueryInstance, TrackingGroup } from '../types';
+
+export function pairEventKey(trait: Trait, target: Entity) {
+    return `${trait.id}:${target}`;
+}
+
+export function recordPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    type: EventType
+) {
+    const eventsByTracker = world[$internal].pairTrackingEvents;
+    const key = pairEventKey(trait, target);
+    for (const events of eventsByTracker.values()) {
+        let entityEvents = events.get(entity);
+        if (!entityEvents) events.set(entity, (entityEvents = new Map()));
+        const previous = entityEvents.get(key);
+        // Structural opposites in one observation window cancel each other.
+        if ((previous === 'add' && type === 'remove') || (previous === 'remove' && type === 'add')) {
+            entityEvents.delete(key);
+        } else {
+            entityEvents.set(key, type);
+        }
+    }
+}
+
+export function groupHasPairEvent(world: World, group: TrackingGroup, entity: Entity): boolean {
+    if (!group.pairs.length) return true;
+    const events = world[$internal].pairTrackingEvents.get(group.id)?.get(entity);
+    if (!events) return false;
+    for (const pair of group.pairs) {
+        const ctx = pair[$internal];
+        const trait = ctx.relation[$internal].trait;
+        if (ctx.target === '*') {
+            let found = false;
+            for (const [key, type] of events) {
+                if (type === group.type && key.startsWith(`${trait.id}:`)) {
+                    found = true;
+                    break;
+                }
+            }
+            if (!found) return false;
+        } else if (events.get(pairEventKey(trait, ctx.target)) !== group.type) {
+            return false;
+        }
+    }
+    return true;
+}
+
+export function clearPairTrackingEvents(world: World, query: QueryInstance, entity: Entity) {
+    const events = world[$internal].pairTrackingEvents;
+    const eid = getEntityId(entity);
+    for (const group of query.trackingGroups) {
+        if (group.pairs.length) events.get(group.id)?.delete(entity);
+        // pair events are keyed by full entity values, while bitmasks use bare IDs.
+        void eid;
+    }
+}
